package com.example.carstore.entity;
import javax.persistence.*;import java.util.Date;
@Entity @Table(name="Promotion",schema="dbo") public class Promotion{
 @Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Integer id;@Column(name="title")private String name;private String code;private String type;private Double value;private String description;@Column(name="discount_percent")private Integer discountPercent;@Temporal(TemporalType.DATE)@Column(name="start_date")private Date startDate;@Temporal(TemporalType.DATE)@Column(name="end_date")private Date endDate;private Boolean status;@Temporal(TemporalType.TIMESTAMP)@Column(name="created_at")private Date createdAt;
 public Integer getId(){return id;}public void setId(Integer v){id=v;}public String getName(){return name;}public void setName(String v){name=v;}public String getCode(){return code;}public void setCode(String v){code=v;}public String getType(){return type;}public void setType(String v){type=v;}public Double getValue(){return value;}public void setValue(Double v){value=v;}public String getDescription(){return description;}public void setDescription(String v){description=v;}public Integer getDiscountPercent(){return discountPercent;}public void setDiscountPercent(Integer v){discountPercent=v;}public Date getStartDate(){return startDate;}public void setStartDate(Date v){startDate=v;}public Date getEndDate(){return endDate;}public void setEndDate(Date v){endDate=v;}public Boolean getStatus(){return status;}public void setStatus(Boolean v){status=v;}public Date getCreatedAt(){return createdAt;}public void setCreatedAt(Date v){createdAt=v;}
}
